"use client";

import { Moon, Sun } from "lucide-react";
import { useTheme } from "next-themes";

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

export default function ThemeSelector() {
  const { setTheme, theme } = useTheme();

  const handleThemeChange = (newTheme: string) => {
    // Ensure only valid theme values are set
    const validThemes = ["light", "dark", "system"];
    if (validThemes.includes(newTheme)) {
      setTheme(newTheme);
    }
  };

  return (
    <DropdownMenu modal={false}>
      <DropdownMenuTrigger asChild>
        <Button variant="outline" size="icon">
          <Sun className="h-[1.2rem] w-[1.2rem] scale-100 rotate-0 transition-all dark:scale-0 dark:-rotate-90" />
          <Moon className="absolute h-[1.2rem] w-[1.2rem] scale-0 rotate-90 transition-all dark:scale-100 dark:rotate-0" />
          <span className="sr-only">Toggle theme</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuItem onClick={() => handleThemeChange("light")}>
          Light
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleThemeChange("dark")}>
          Dark
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleThemeChange("system")}>
          System
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import { NextResponse } from "next/server";
import path from "path";
import fs from "fs";

export const runtime = "nodejs";

interface ReviewMetrics {
  totalReviews: number;
  reviewsLast7Days: number;
  reviewsLast30Days: number;
  averageReviewTimeHours: number;
  topReviewers: Array<{
    username: string;
    reviewCount: number;
    avatarUrl: string;
  }>;
  reviewVelocity: {
    daily: number;
    weekly: number;
    monthly: number;
  };
  dailyReviewData: Array<{
    date: string;
    reviews: number;
    avgTimeHours: number;
  }>;
  reviewStateDistribution: {
    approved: number;
    changesRequested: number;
    commented: number;
    pending: number;
  };
  prsNeedingReview: Array<{
    number: number;
    title: string;
    author: string;
    authorAvatar: string;
    createdAt: string;
    url: string;
    repository: string;
    ageHours: number;
    isDraft: boolean;
  }>;
  prsReadyToMerge: Array<{
    number: number;
    title: string;
    author: string;
    authorAvatar: string;
    createdAt: string;
    url: string;
    repository: string;
    approvals: number;
    ageHours: number;
  }>;
}

interface IssueMetrics {
  totalIssues: number;
  openIssues: number;
  closedIssues: number;
  pendingTriage: number;
  recentlyTriaged: number;
  triageVelocity: {
    daily: number;
    weekly: number;
  };
  ageDistribution: {
    lessThan24h: number;
    oneToSevenDays: number;
    sevenToThirtyDays: number;
    moreThanThirtyDays: number;
  };
  dailyTriageData: Array<{
    date: string;
    triaged: number;
    pending: number;
    total: number;
  }>;
  issuesPendingTriage: Array<{
    number: number;
    title: string;
    author: string;
    authorAvatar: string;
    createdAt: string;
    url: string;
    repository: string;
    ageHours: number;
    labels: string[];
  }>;
}

interface AnalyticsData {
  organization: string;
  lastUpdated: string;
  reviewMetrics: ReviewMetrics;
  issueMetrics: IssueMetrics;
  repositories: number;
}

export async function GET(request: Request) {
  try {
    // Read analytics data from the generated JSON file
    const analyticsPath = path.join(process.cwd(), 'public', 'analytics', 'analytics.json');
    
    if (!fs.existsSync(analyticsPath)) {
      return NextResponse.json({ 
        error: "Analytics data not found. Please run 'npm run generate:analytics' to generate the data." 
      }, { status: 404 });
    }
    
    const analyticsData: AnalyticsData = JSON.parse(fs.readFileSync(analyticsPath, 'utf-8'));

    // Always return all analytics data
    return NextResponse.json(analyticsData, {
      headers: {
        'Cache-Control': 'public, s-maxage=300, stale-while-revalidate=600',
      },
    });

  } catch (error) {
    console.error("Error reading analytics data:", error);
    return NextResponse.json(
      { 
        error: "Failed to read analytics data", 
        details: error instanceof Error ? error.message : "Unknown error",
        suggestion: "Try running 'npm run generate:analytics' to generate fresh data."
      },
      { status: 500 }
    );
  }
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { ExternalLink, Clock, CheckCircle, GitMerge } from "lucide-react";
import Link from "next/link";

interface PullRequest {
  number: number;
  title: string;
  author: string;
  authorAvatar: string;
  createdAt: string;
  url: string;
  repository: string;
  approvals: number;
  ageHours: number;
}

interface AnalyticsData {
  reviewMetrics: {
    prsReadyToMerge: PullRequest[];
  };
}

export function ReadyToMergeList() {
  const [data, setData] = useState<AnalyticsData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchData() {
      try {
        const response = await fetch('/api/analytics');
        if (!response.ok) {
          throw new Error('Failed to fetch PRs ready to merge');
        }
        const result = await response.json();
        setData(result);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred');
      } finally {
        setIsLoading(false);
      }
    }

    fetchData();
  }, []);

  const formatAge = (hours: number) => {
    if (hours < 24) {
      return `${Math.round(hours)}h ago`;
    } else if (hours < 24 * 7) {
      return `${Math.round(hours / 24)}d ago`;
    } else {
      return `${Math.round(hours / 24 / 7)}w ago`;
    }
  };

  if (isLoading) {
    return (
      <Card>
        <CardHeader>
          <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-1/2 animate-pulse"></div>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {[1, 2, 3, 4, 5].map((i) => (
              <div key={i} className="flex items-center space-x-3 animate-pulse">
                <div className="h-10 w-10 bg-gray-200 dark:bg-gray-700 rounded-full"></div>
                <div className="flex-1 space-y-2">
                  <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-3/4"></div>
                  <div className="h-3 bg-gray-200 dark:bg-gray-700 rounded w-1/2"></div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  if (error) {
    return (
      <Card>
        <CardContent className="pt-6">
          <div className="text-center text-red-600 dark:text-red-400">
            Error loading PRs ready to merge: {error}
          </div>
        </CardContent>
      </Card>
    );
  }

  const prsReadyToMerge = data?.reviewMetrics?.prsReadyToMerge || [];

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <GitMerge className="h-5 w-5" />
          PRs Ready to Merge ({prsReadyToMerge.length})
        </CardTitle>
        <CardDescription>
          Pull requests that have been approved and are ready for merging
        </CardDescription>
      </CardHeader>
      <CardContent>
        {prsReadyToMerge.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            No PRs ready to merge at the moment
          </div>
        ) : (
          <div className="max-h-96 overflow-y-auto">
            <div className="space-y-4">
              {prsReadyToMerge.map((pr) => (
              <div key={`${pr.repository}-${pr.number}`} className="flex items-start space-x-3 p-3 rounded-lg border bg-card hover:bg-accent/50 transition-colors">
                <Avatar className="h-8 w-8 mt-1">
                  <AvatarImage src={pr.authorAvatar} alt={pr.author || 'Unknown'} />
                  <AvatarFallback>{(pr.author || '?').slice(0, 2).toUpperCase()}</AvatarFallback>
                </Avatar>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <Badge variant="outline" className="text-xs">
                      {pr.repository}
                    </Badge>
                    <Badge variant="secondary" className="text-xs">
                      #{pr.number}
                    </Badge>
                  </div>
                  <Link 
                    href={pr.url} 
                    target="_blank"
                    rel="noopener noreferrer"
                    className="font-medium text-sm hover:underline flex items-center gap-1"
                  >
                    {pr.title}
                    <ExternalLink className="h-3 w-3" />
                  </Link>
                  <div className="flex items-center gap-4 mt-2 text-xs text-muted-foreground">
                    <span>by {pr.author}</span>
                    <span className="flex items-center gap-1">
                      <Clock className="h-3 w-3" />
                      {formatAge(pr.ageHours)}
                    </span>
                  </div>
                </div>
              </div>
            ))}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { GitPullRequest, Clock, TrendingUp, Users, Divide } from "lucide-react";

interface ReviewMetrics {
  totalReviews: number;
  reviewsLast7Days: number;
  reviewsLast30Days: number;
  averageReviewTimeHours: number;
  reviewVelocity: {
    daily: number;
    weekly: number;
    monthly: number;
  };
}

interface AnalyticsData {
  reviewMetrics: ReviewMetrics;
  lastUpdated: string;
}

export function ReviewMetricsCard() {
  const [data, setData] = useState<AnalyticsData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchData() {
      try {
        const response = await fetch('/api/analytics');
        if (!response.ok) {
          throw new Error('Failed to fetch review metrics');
        }
        const result = await response.json();
        setData(result);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred');
      } finally {
        setIsLoading(false);
      }
    }

    fetchData();
  }, []);

  if (isLoading) {
    return (
      <>
        {[1, 2, 3, 4].map((i) => (
          <Card key={i} className="animate-pulse w-full min-h-30">
            <CardHeader className="pb-2">
              <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-3/4"></div>
            </CardHeader>
            <CardContent>
              <div className="h-8 bg-gray-200 dark:bg-gray-700 rounded w-1/2 mb-2"></div>
              <div className="h-3 bg-gray-200 dark:bg-gray-700 rounded w-full"></div>
            </CardContent>
          </Card>
        ))}
      </>
    );
  }

  if (error) {
    return (
      <Card className="col-span-full">
        <CardContent className="pt-6">
          <div className="text-center text-red-600 dark:text-red-400">
            Error loading review metrics: {error}
          </div>
        </CardContent>
      </Card>
    );
  }

  if (!data) return null;

  const metrics = data.reviewMetrics;
  const changePercent = metrics.reviewsLast30Days > 0
    ? Math.round((metrics.reviewsLast7Days * 4 - metrics.reviewsLast30Days) / metrics.reviewsLast30Days * 100)
    : 0;

  return (
    <>
      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Total Reviews</CardTitle>
          <GitPullRequest className="h-4 w-4 text-muted-foreground" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{metrics.totalReviews}</div>
          <p className="text-xs text-muted-foreground">
            {metrics.reviewsLast7Days} this week
          </p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Avg Review Time</CardTitle>
          <Clock className="h-4 w-4 text-muted-foreground" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">
            {metrics.averageReviewTimeHours < 24
              ? `${metrics.averageReviewTimeHours}h`
              : `${Math.round(metrics.averageReviewTimeHours / 24)}d`
            }
          </div>
          <p className="text-xs text-muted-foreground">
            Time to first review
          </p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Review Velocity</CardTitle>
          <TrendingUp className="h-4 w-4 text-muted-foreground" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{Math.round(metrics.reviewVelocity.daily * 10) / 10}</div>
          <p className="text-xs text-muted-foreground">
            Reviews per day
          </p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Weekly Trend</CardTitle>
          <Users className="h-4 w-4 text-muted-foreground" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{metrics.reviewsLast7Days}</div>
          <div className="flex items-center text-xs text-muted-foreground">
            {changePercent !== 0 && (
              <Badge
                variant={changePercent > 0 ? "default" : "secondary"}
                className={`mr-1 ${changePercent > 0 ? 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200' : 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200'}`}
              >
                {changePercent > 0 ? '+' : ''}{changePercent}%
              </Badge>
            )}
            vs last 30 days (projected)
          </div>
        </CardContent>
      </Card>
    </>
  );
}

"use client";

import { Card, CardContent } from "@/components/ui/card";
import { Avatar, AvatarImage, AvatarFallback } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Trophy, GitMerge, GitPullRequest, AlertCircle, Eye, Tag, UserPlus, CheckCircle, Flame, Clock, ExternalLink, FlameIcon } from "lucide-react";
import { cn } from "@/lib/utils";
import ActivityTrendChart from "./ActivityTrendChart";
import "./LeaderboardCard.css";

const activityStyles: Record<string, {
  icon: React.ComponentType<{ className?: string }>;
  bgColor: string;
  textColor: string;
  borderColor: string;
}> = {
  "PR merged": {
    icon: GitMerge,
    bgColor: "bg-purple-500/10 dark:bg-purple-500/15",
    textColor: "text-purple-700 dark:text-purple-400",
    borderColor: "border-l-purple-500"
  },
  "PR opened": {
    icon: GitPullRequest,
    bgColor: "bg-blue-500/10 dark:bg-blue-500/15",
    textColor: "text-blue-700 dark:text-blue-400",
    borderColor: "border-l-blue-500"
  },
  "Issue opened": {
    icon: AlertCircle,
    bgColor: "bg-orange-500/10 dark:bg-orange-500/15",
    textColor: "text-orange-700 dark:text-orange-400",
    borderColor: "border-l-orange-500"
  },
  "Review submitted": {
    icon: Eye,
    bgColor: "bg-green-500/10 dark:bg-green-500/15",
    textColor: "text-green-700 dark:text-green-400",
    borderColor: "border-l-green-500"
  },
  "Issue labeled": {
    icon: Tag,
    bgColor: "bg-yellow-500/10 dark:bg-yellow-500/15",
    textColor: "text-yellow-700 dark:text-yellow-400",
    borderColor: "border-l-yellow-500"
  },
  "Issue assigned": {
    icon: UserPlus,
    bgColor: "bg-indigo-500/10 dark:bg-indigo-500/15",
    textColor: "text-indigo-700 dark:text-indigo-400",
    borderColor: "border-l-indigo-500"
  },
  "Issue closed": {
    icon: CheckCircle,
    bgColor: "bg-emerald-500/10 dark:bg-emerald-500/15",
    textColor: "text-emerald-700 dark:text-emerald-400",
    borderColor: "border-l-emerald-500"
  }
};

const getActivityStyle = (activityName: string) => {
  return activityStyles[activityName] || {
    icon: () => null,
    bgColor: "bg-muted",
    textColor: "text-muted-foreground",
    borderColor: "border-l-gray-400"
  };
};

export type LeaderboardEntry = {
  username: string;
  name: string | null;
  avatar_url: string | null;
  role?: string | null;
  total_points: number;
  activity_breakdown: Record<
    string,
    {
      count: number;
      points: number;
    }
  >;
  daily_activity?: Array<{
    date: string;
    points: number;
    count: number;
  }>;
  streak?: {
    current: number;
    longest: number;
    lastActivityDate: string | null;
  };
  active_prs?: Array<{ title: string; link: string; updatedAt: string }>;
  stale_prs?: Array<{ title: string; link: string; updatedAt: string }>;
};

interface LeaderboardCardProps {
  entry: LeaderboardEntry;
  rank: number;
  startDate: Date;
  endDate: Date;
  variant?: "grid" | "list";
}

export function LeaderboardCard({
  entry,
  rank,
  startDate,
  endDate,
  variant = "grid"
}: LeaderboardCardProps) {
  const isTopThree = rank <= 3;

  // Helper function to sort activities by priority then alphabetically
  const sortActivitiesByPriority = (entries: Array<[string, { count: number; points: number }]>) => {
    return entries.sort((a, b) => {
      const activityPriority: Record<string, number> = {
        "PR merged": 1,
        "PR opened": 2,
        "Issue closed": 3,
        "Issue assigned": 4,
        "Issue opened": 5,
        "Issue labeled": 6,
        "Review submitted": 7,
      };
      const priorityA = activityPriority[a[0]] ?? 99;
      const priorityB = activityPriority[b[0]] ?? 99;
      if (priorityA !== priorityB) {
        return priorityA - priorityB;
      }
      return a[0].localeCompare(b[0]);
    });
  };

  const openGitHubProfile = () => {
    if (entry.username && /^[a-zA-Z0-9](?:[a-zA-Z0-9-]*[a-zA-Z0-9])?$/.test(entry.username)) {
      window.open(`https://github.com/${encodeURIComponent(entry.username)}`, '_blank', 'noopener,noreferrer');
    }
  };

  const getRankIcon = (rank: number) => {
    if (rank === 1)
      return <Trophy className="h-4 w-4 text-yellow-600 dark:text-yellow-500" aria-label="1st place" />;
    if (rank === 2)
      return <Trophy className="h-4 w-4 text-gray-500 dark:text-gray-400" aria-label="2nd place" />;
    if (rank === 3)
      return <Trophy className="h-4 w-4 text-amber-700 dark:text-amber-600" aria-label="3rd place" />;
    return null;
  };

  const getRankStyles = (rank: number) => {
    if (rank <= 3) {
      return {
        border: "border-[#50B78B]/50",
        iconBg: "bg-[#42B883]/10"
      };
    }

    return {
      border: "",
      iconBg: "bg-[#42B883]"
    };
  };

  const getAnimatedBorderClass = (rank: number) => {
    if (rank === 1) return "rank-card-1";
    if (rank === 2) return "rank-card-2";
    if (rank === 3) return "rank-card-3";
    return "";
  };

  const styles = getRankStyles(rank);

  if (variant === "list") {
    return (
      <div className={cn(
        "relative group",
        isTopThree && getAnimatedBorderClass(rank)
      )}>
        <Card
          className={cn(
            "relative z-10 overflow-hidden transition-all duration-500 border-2 h-full flex flex-col",
            styles.border,
            "hover:shadow-2xl hover:-translate-y-1"
          )}
        >
          {/* Glossy Shine Effect */}
