}

"use client";
import { Card, CardContent } from "@/components/ui/card";
import { Avatar, AvatarImage, AvatarFallback } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import Link from "next/link";
import {
  ChevronLeft,
  ChevronRight,
  Filter,
  X,
  Medal,
  Trophy,
  GitMerge,
  GitPullRequest,
  AlertCircle,
  Search, Grid3X3, List,
  SearchX,
  Eye,
  Tag,
  CheckCircle,
  Loader2
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useMemo, useState, useEffect, useRef } from "react";
import { sortEntries, type SortBy } from "@/lib/leaderboard";
import { useRouter, useSearchParams, usePathname } from "next/navigation";
import { Input } from "@/components/ui/input";
import { LeaderboardCard, type LeaderboardEntry } from "./LeaderboardCard";
import { LeaderboardCardsSkeleton } from "./LeaderboardSkeleton";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

interface LeaderboardViewProps {
  entries: LeaderboardEntry[];
  period: "week" | "month" | "year";
  startDate: Date;
  endDate: Date;
  topByActivity: Record<
    string,
    Array<{
      username: string;
      name: string | null;
      avatar_url: string | null;
      points: number;
      count: number;
    }>
  >;
  hiddenRoles: string[];
}

// Activity type styling configuration
const activityStyles: Record<string, {
  icon: React.ComponentType<{ className?: string }>;
  bgColor: string;
  textColor: string;
  borderColor: string;
}> = {
  "PR merged": {
    icon: GitMerge,
    bgColor: "bg-purple-500/10 dark:bg-purple-500/15",
    textColor: "text-purple-700 dark:text-purple-400",
    borderColor: "border-l-purple-500"
  },
  "PR opened": {
    icon: GitPullRequest,
    bgColor: "bg-blue-500/10 dark:bg-blue-500/15",
    textColor: "text-blue-700 dark:text-blue-400",
    borderColor: "border-l-blue-500"
  },
  "Issue opened": {
    icon: AlertCircle,
    bgColor: "bg-orange-500/10 dark:bg-orange-500/15",
    textColor: "text-orange-700 dark:text-orange-400",
    borderColor: "border-l-orange-500"
  },
  "Issue closed": {
    icon: CheckCircle,
    bgColor: "bg-green-500/10 dark:bg-green-500/15",
    textColor: "text-green-700 dark:text-green-400",
    borderColor: "border-l-green-500"
  },
  "Issue labeled": {
    icon: Tag,
    bgColor: "bg-pink-500/10 dark:bg-pink-500/15",
    textColor: "text-pink-700 dark:text-pink-400",
    borderColor: "border-l-pink-500"
  },
  "Review submitted": {
    icon: Eye,
    bgColor: "bg-teal-500/10 dark:bg-teal-500/15",
    textColor: "text-teal-700 dark:text-teal-400",
    borderColor: "border-l-teal-500"
  }
};

const getActivityStyle = (activityName: string) => {
  return activityStyles[activityName] || {
    icon: () => null,
    bgColor: "bg-muted",
    textColor: "text-muted-foreground",
    borderColor: "border-l-gray-400"
  };
};

function useDebounce<T>(value: T, delay = 400): T {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => clearTimeout(handler);
  }, [value, delay]);

  return debouncedValue;
}


export default function LeaderboardView({
  entries,
  period,
  startDate,
  endDate,
  topByActivity,
  hiddenRoles,
}: LeaderboardViewProps) {
  const router = useRouter();
  const searchParams = useSearchParams();

  const [searchQuery, setSearchQuery] = useState("");
  const debouncedSearchQuery = useDebounce(searchQuery, 300);

  const [periodLoading, setPeriodLoading] = useState(false);
  const [selectedPeriod, setSelectedPeriod] = useState<"week" | "month" | "year">(period);

  // Page size state - default to showing top 50 for better readability and performance
  const [pageSize, setPageSize] = useState<number>(() => {
    const limit = searchParams.get('limit');
    if (limit) {
      if (limit === 'all') {
        return Infinity;
      }
      const parsed = parseInt(limit, 10);
      if ([10, 25, 50, 100].includes(parsed)) {
        return parsed;
      }
    }
    // Default: show top 50 entries for better UX and performance
    return 50;
  });

  useEffect(() => {
    const limit = searchParams.get('limit');
    if (limit) {
      if (limit === 'all') {
        setPageSize(Infinity);
        return;
      }
      const parsed = parseInt(limit, 10);
      if ([10, 25, 50, 100].includes(parsed)) {
        setPageSize(parsed);
      } else {
        setPageSize(50);
      }
    } else {
      setPageSize(50);
    }
  }, [searchParams]);

  // Current page state - default to page 1
  const [currentPage, setCurrentPage] = useState<number>(() => {
    const page = searchParams.get('page');
    if (page) {
      const parsed = parseInt(page, 10);
      return parsed > 0 ? parsed : 1;
    }
    return 1;
  });

  useEffect(() => {
    const page = searchParams.get('page');
    if (page) {
      const parsed = parseInt(page, 10);
      setCurrentPage(parsed > 0 ? parsed : 1);
    } else {
      setCurrentPage(1);
    }
  }, [searchParams]);

  // sorting
  const [sortBy, setSortBy] = useState<SortBy>(() => {
    const s = searchParams.get('sort');
    if (s === 'pr_opened' || s === 'pr_merged' || s === 'issues' || s === 'reviews' || s === 'issue_closed' || s === 'issue_labeled')
      return s as SortBy;
    return 'points';
  });

  useEffect(() => {
    const s = searchParams.get('sort');
    setSortBy(s === 'pr_opened' || s === 'pr_merged' || s === 'issues' || s === 'reviews' || s === 'issue_closed' || s === 'issue_labeled' ? (s as SortBy) : 'points');
  }, [searchParams]);

  const [popoverOpen, setPopoverOpen] = useState(false);
  const pathname = usePathname();

  // Initialize from URL param (works on server and client)
  const [viewMode, setViewMode] = useState<"grid" | "list">(() => {
    const v = searchParams.get("v");
    return v === "grid" ? "grid" : "list";
  });

  // On mobile/tablet, always force list mode after mount
  useEffect(() => {
    if (typeof window !== "undefined" && window.innerWidth < 1024) {
      setViewMode("list");
    }
  }, []);

  // Sync with URL param changes (for desktop)
  useEffect(() => {
    const v = searchParams.get("v");
    if (typeof window !== "undefined" && window.innerWidth >= 1024) {
      setViewMode(v === "grid" ? "grid" : "list");
    }
  }, [searchParams]);
  const topRef = useRef<HTMLDivElement | null>(null);
  const scrollToLeaderboardTop = () => {
    if (typeof window === "undefined") return;
    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;

    requestAnimationFrame(() => {
      if (!topRef.current) return;

      const rect = topRef.current.getBoundingClientRect();
      const absoluteTop = rect.top + window.scrollY;
      const offset = 80;

      window.scrollTo({
        top: Math.max(absoluteTop - offset, 0),
        behavior: prefersReducedMotion ? "auto" : "smooth",
      });
    });
  };

  const handleViewModeChange = (mode: "grid" | "list") => {
    // Prevent grid view on mobile/tablet
    if (typeof window !== "undefined" && window.innerWidth < 1024 && mode === "grid") {
      return;
    }
    setViewMode(mode);
    const params = new URLSearchParams(searchParams.toString());
    if (mode === "list") {
      params.delete("v");
    } else {
      params.set("v", mode);
    }
    if (typeof window !== "undefined") {
      window.history.replaceState(null, "", `${pathname}?${params.toString()}`);
    }
  };

  // Get selected roles from query params
  // If no roles are selected, default to all visible roles (excluding hidden ones)
  const selectedRoles = useMemo(() => {
    const rolesParam = searchParams.get("roles");
    if (rolesParam) {
      return new Set(rolesParam.split(","));
    }
    const allRoles = new Set<string>();
    entries.forEach((entry) => {
      if (entry.role && !hiddenRoles.includes(entry.role)) {
        allRoles.add(entry.role);
      }
    });
    return allRoles;
  }, [searchParams, entries, hiddenRoles]);

  const availableRoles = useMemo(() => {
    const roles = new Set<string>();
    entries.forEach((entry) => {
      if (entry.role) {
        roles.add(entry.role);
      }
    });
    return Array.from(roles).sort();
  }, [entries]);

  // Calculate ranks based on current sort criteria
  // Rank is independent of search query and pagination
  // When role filtering is active, ranks are computed within the filtered subset
  const entryRanks = useMemo(() => {
    // Filter by selectedRoles (same logic as filteredEntries, but no search filter)
    let entriesForRanking = entries;

    if (selectedRoles.size > 0) {
      entriesForRanking = entriesForRanking.filter(
        (entry) => entry.role && selectedRoles.has(entry.role)
      );
    }

    // Sort by current sort criteria and calculate ranks
    const sorted = sortEntries(entriesForRanking, sortBy);
    const rankMap = new Map<string, number>();
    sorted.forEach((entry, index) => {
      rankMap.set(entry.username, index + 1);
    });
    return rankMap;
  }, [entries, selectedRoles, sortBy]);

  const filteredEntries = useMemo(() => {
    let filtered = entries;

    if (selectedRoles.size > 0) {
      filtered = filtered.filter(
        (entry) => entry.role && selectedRoles.has(entry.role)
      );
    }

    if (debouncedSearchQuery.trim()) {
      const query = debouncedSearchQuery.toLowerCase();
      filtered = filtered.filter((entry) => {
        const name = (entry.name || entry.username).toLowerCase();
        const username = entry.username.toLowerCase();
        return name.includes(query) || username.includes(query);
      });
    }


    // applying sorting
    try {
      filtered = sortEntries(filtered, sortBy);
    }
    catch (e) {
      console.error('Error sorting entries:', e);
    }

    return filtered;
  }, [entries, selectedRoles, debouncedSearchQuery, sortBy]);

  // Calculate total pages
  const totalPages = useMemo(() => {
    if (pageSize === Infinity) {
      return 1; // Show all entries on one "page"
    }
    return Math.ceil(filteredEntries.length / pageSize);
  }, [filteredEntries.length, pageSize]);

  // Slice entries based on pageSize and currentPage
  const paginatedEntries = useMemo(() => {
    if (pageSize === Infinity) {
      return filteredEntries;
    }
    const start = (currentPage - 1) * pageSize;
    const end = start + pageSize;
    return filteredEntries.slice(start, end);
  }, [filteredEntries, pageSize, currentPage]);

  // Reset to page 1 when pageSize changes or when filteredEntries change significantly
  useEffect(() => {
    if (currentPage > totalPages && totalPages > 0) {
      const params = new URLSearchParams(searchParams.toString());
      params.delete("page");
      setCurrentPage(1);

      if (typeof window !== "undefined") {
        window.history.replaceState(null, "", `${pathname}?${params.toString()}`);
      }
    }
  }, [
    debouncedSearchQuery,
    pageSize,
    totalPages,
    currentPage,
    searchParams,
    pathname,
  ]);



  // Reset to page 1 when search query changes
  useEffect(() => {
    if (currentPage !== 1 && pageSize !== Infinity) {
      const params = new URLSearchParams(searchParams.toString());
      params.delete("page");
      setCurrentPage(1);
      if (typeof window !== 'undefined') {
        window.history.replaceState(null, '', `${pathname}?${params.toString()}`);
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [debouncedSearchQuery]); // Only reset when search query changes

  const toggleRole = (role: string) => {
    const newSelected = new Set(selectedRoles);
    if (newSelected.has(role)) {
      newSelected.delete(role);
    } else {
      newSelected.add(role);
    }
    // Reset to page 1 when roles change
    const params = new URLSearchParams(searchParams.toString());
    if (newSelected.size > 0) {
      params.set("roles", Array.from(newSelected).join(","));
    } else {
      params.delete("roles");
    }
    params.delete("page"); // Reset pagination
    if (typeof window !== 'undefined') {
      window.history.replaceState(null, '', `${pathname}?${params.toString()}`);
    }
    setCurrentPage(1);
  };

  const clearFilters = () => {
    const isMobile = typeof window !== "undefined" && window.innerWidth < 640;
    const params = new URLSearchParams(searchParams.toString());
    if (isMobile) {
      setSearchQuery("");
      return;
    }
    params.delete("roles");
    params.delete("sort");
    params.delete("order");
    // Reset to page 1 when clearing filters
    params.delete("page");
    setCurrentPage(1);
    // Note: We preserve the limit param when clearing filters

    window.history.replaceState(null, "", `${pathname}?${params.toString()}`);
    setSearchQuery("");
    setSortBy("points");
  };

  const updatePageSize = (newPageSize: number | "all") => {
    const params = new URLSearchParams(searchParams.toString());
    if (newPageSize === "all" || newPageSize === Infinity) {
      params.set("limit", "all");
      setPageSize(Infinity);
    } else {
      params.set("limit", newPageSize.toString());
      setPageSize(newPageSize);
    }
    // Reset to page 1 when page size changes
    params.delete("page");
    setCurrentPage(1);
    if (typeof window !== 'undefined') {
      window.history.replaceState(null, '', `${pathname}?${params.toString()}`);
    }
  };

  const updatePage = (page: number) => {
    const params = new URLSearchParams(searchParams.toString());
    if (page === 1) {
      params.delete("page");
    } else {
      params.set("page", page.toString());
    }
    setCurrentPage(page);
    scrollToLeaderboardTop();
    if (typeof window !== 'undefined') {
      window.history.replaceState(null, '', `${pathname}?${params.toString()}`);
    }
  };

  const goToNextPage = () => {
    if (currentPage < totalPages) {
      updatePage(currentPage + 1);
    }
  };


  const goToPreviousPage = () => {
    if (currentPage > 1) {
      updatePage(currentPage - 1);
    }
  };

  const goToPage = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      updatePage(page);
    }
  };

  const updateRolesParam = (roles: Set<string>) => {
    const params = new URLSearchParams(searchParams.toString());
    if (roles.size > 0) {
      params.set("roles", Array.from(roles).join(","));
    } else {
      params.delete("roles");
    }
    if (typeof window !== 'undefined') window.history.replaceState(null, '', `${pathname}?${params.toString()}`);
  };

  const handlePeriodChange = (newPeriod: "week" | "month" | "year") => {
    if (periodLoading || newPeriod === selectedPeriod) return;
    
    setPeriodLoading(true);
    setSelectedPeriod(newPeriod);

    try {
      const params = new URLSearchParams(searchParams.toString());
      params.delete("page");
      const href = `/leaderboard/${newPeriod}${params.toString() ? `?${params.toString()}` : ''}`;
      
      router.push(href);
    } catch {
      setPeriodLoading(false);
      setSelectedPeriod(period);
    }
  };

  const filteredTopByActivity = useMemo(() => {
    if (selectedRoles.size === 0) {
      return topByActivity;
    }

    const filtered: typeof topByActivity = {};

    for (const [activityName, contributors] of Object.entries(topByActivity)) {
      const filteredContributors = contributors.filter((contributor) => {
        const entry = entries.find((e) => e.username === contributor.username);
        return entry?.role && selectedRoles.has(entry.role);
      });

      if (filteredContributors.length > 0) {
        filtered[activityName] = filteredContributors;
      }
    }

    return filtered;
  }, [topByActivity, selectedRoles, entries]);

  const periodLabels = {
    week: "Weekly",
    month: "Monthly",
    year: "Yearly",
  };

  // Reset loading state when period actually changes
  useEffect(() => {
    setPeriodLoading(false);
    setSelectedPeriod(period);
  }, [period]);

  return (
    <div ref={topRef} className="container mx-auto px-4 py-8">
      <div className="flex gap-8">
        {/* Main Content */}
        <div className="flex-1 min-w-0">
          {/* Header */}
          <div className="mb-8">
            <div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between mb-4">
              <div className="min-w-0">
                <h1 className="text-4xl text-[#50B78B] font-bold mb-2">
                  {periodLabels[period]} Leaderboard
                </h1>
                <p className="text-muted-foreground">
                  {filteredEntries.length} of {entries.length} contributors
                  {(selectedRoles.size > 0 || searchQuery) && " (filtered)"}
                </p>
              </div>

              {/* Filters */}
              <div
                className="
                  w-full
                  lg:w-auto lg:ml-auto
                  flex flex-col
                  lg:flex-row lg:items-center
                  gap-2
                "
              >
                {/* Search bar - full width on mobile/tablet */}
                <div className="relative w-full lg:w-[16rem]">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    type="text"
                    placeholder="Search contributors..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="pl-9 h-9 w-full bg-white dark:bg-[#07170f] border border-[#50B78B]/60 dark:border-[#50B78B]/40 focus-visible:ring-2 focus-visible:ring-[#50B78B]"
                  />
                </div>

                {/* Controls row - grid/list on left, filter on right */}
                <div className="flex items-center justify-between w-full lg:w-auto lg:justify-end gap-2">
                  <div className="flex items-center gap-2">
                    {/* Hide grid/list toggle on mobile/tablet, show only on desktop */}
                    <div className="hidden lg:flex w-fit items-center justify-center gap-1 p-1 bg-muted rounded-lg">
                      <Button
                        variant={viewMode === "list" ? "default" : "ghost"}
                        size="sm"
                        onClick={() => handleViewModeChange("list")}
                        className={cn(
                          "h-8 px-3",
                          viewMode === "list"
                            ? "bg-[#50B78B] hover:bg-[#50B78B]/90 text-white"
                            : "hover:bg-[#50B78B]/10 text-muted-foreground"
                        )}
                      >
                        <List className="h-4 w-4" />
                      </Button>
                      <Button
                        variant={viewMode === "grid" ? "default" : "ghost"}
                        size="sm"
                        onClick={() => handleViewModeChange("grid")}
                        className={cn(
                          "h-8 px-3",
                          viewMode === "grid"
                            ? "bg-[#50B78B] hover:bg-[#50B78B]/90 text-white"
                            : "hover:bg-[#50B78B]/10 text-muted-foreground"
                        )}
                      >
                        <Grid3X3 className="h-4 w-4" />
                      </Button>
                    </div>

                    <div className="hidden md:flex">
                      <button
                        type="button"
                        className="h-9 w-28 px-3 rounded-md bg-[#50B78B] text-white text-sm flex items-center justify-center gap-2"
                      >
                        <span>
                          {sortBy === "points"
                            ? "Total Points"
                            : sortBy === "pr_opened"
                              ? "PR Opened"
                              : sortBy === "pr_merged"
                                ? "PR Merged"
                                : sortBy === "issue_closed"
                                    ? "Issue Closed"
                                    : sortBy === "issue_labeled"
                                      ? "Issue Labeled"
                                      : sortBy === "reviews"
                                        ? "Review Submitted"
                                        : "Issue Opened"}
                        </span>
                      </button>
                    </div>
                  </div>

                  <div className="flex items-center gap-2">
                    {(selectedRoles.size > 0 || searchQuery || sortBy !== "points") && (
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={clearFilters}
                        className="h-9 hover:bg-[#50B78B]/20 cursor-pointer"
                      >
                        <X className="h-4 w-4 mr-1" />
                        Clear
                      </Button>
                    )}

                    <Popover open={popoverOpen} onOpenChange={setPopoverOpen}>
                      <PopoverTrigger asChild>
                        <Button
                          variant="outline"
                          size="sm"
                          className="h-9 border border-[#50B78B]/30 hover:bg-[#50B78B]/20 cursor-pointer"
                        >
                          <Filter className="h-4 w-4 mr-1.5" />
                          Filter
                          {selectedRoles.size > 0 && (
                            <span className="ml-1 px-1.5 py-0.5 text-xs rounded-full bg-[#50B78B] text-white">
                              {selectedRoles.size}
                            </span>
                          )}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent
                        align="end"
                        className="w-64 bg-white dark:bg-[#07170f] border-[#50B78B]/20"
                      >
                        <div className="space-y-4">
                          {/* Sort By Section */}
                          <div>
                            <h4 className="font-semibold text-sm mb-3 text-foreground">
                              Sort By
                            </h4>
                            <div className="space-y-1">
                              {[
                                { key: 'points' as SortBy, label: 'Total Points' },
                                { key: 'pr_opened' as SortBy, label: 'PRs Opened' },
                                { key: 'pr_merged' as SortBy, label: 'PRs Merged' },
                                { key: 'issues' as SortBy, label: 'Issue Opened' },
                                { key: 'issue_closed' as SortBy, label: 'Issue Closed' },
                                { key: 'issue_labeled' as SortBy, label: 'Issue Labeled' },
                                { key: 'reviews' as SortBy, label: 'Review Submitted' },
                              ].map((opt) => {
                                const active = sortBy === opt.key;
                                return (
                                  <button
                                    key={opt.key}
                                    onClick={(e) => {
                                      setPopoverOpen(false);
                                      setSortBy(opt.key as SortBy);
                                      const params = new URLSearchParams(searchParams.toString());
                                      if (opt.key === 'points') {
                                        params.delete('sort');
                                        params.delete('order');
                                      } else {
                                        params.set('sort', opt.key);
                                        params.set('order', 'desc');
                                      }
                                      params.delete('page');
                                      setCurrentPage(1);
                                      if (typeof window !== 'undefined')
                                        window.history.replaceState(null, '', `${pathname}?${params.toString()}`);
                                    }}
                                    className={cn(
                                      'w-full text-left px-3 py-2 cursor-pointer rounded-md text-sm font-medium transition-all',
                                      active
                                        ? 'bg-[#50B78B] text-white shadow-sm'
                                        : 'hover:bg-[#50B78B]/10 text-foreground'
                                    )}
                                    aria-pressed={active}
                                  >
                                    {opt.label}
                                  </button>
                                )
                              })}
                            </div>
                          </div>

                          {/* Divider */}
                          <div className="border-t border-border" />

                          {/* Role Section */}
                          <div>
                            <h4 className="font-semibold text-sm mb-3 text-foreground">
                              Role
                            </h4>
                            <div className="space-y-2">
                              {availableRoles.map((role) => (
                                <label
                                  key={role}
                                  htmlFor={`role-${role}`}
                                  className={cn(
                                    "flex items-center gap-3 px-3 py-2.5 rounded-lg cursor-pointer transition-all duration-200 group",
                                    selectedRoles.has(role)
                                      ? "bg-[#50B78B]/10 border border-[#50B78B]/30 shadow-sm"
                                      : "bg-muted/30 hover:bg-muted/60 border border-transparent"
                                  )}
                                >
                                  <Checkbox
                                    id={`role-${role}`}
                                    checked={selectedRoles.has(role)}
                                    onCheckedChange={() => toggleRole(role)}
                                    className={cn(
                                      "data-[state=checked]:bg-[#50B78B] data-[state=checked]:border-[#50B78B] border-2",
                                      "transition-all duration-200"
                                    )}
                                  />
                                  <span className={cn(
                                    "text-sm font-medium flex-1 transition-colors",
                                    selectedRoles.has(role)
                                      ? "text-[#50B78B]"
                                      : "text-foreground group-hover:text-[#50B78B]"
                                  )}>
                                    {role}
                                  </span>
                                </label>
                              ))}
                            </div>
                          </div>
                        </div>
                      </PopoverContent>
                    </Popover>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Period Selector */}
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-8 border-b">
            <div className="flex gap-2">
              {(["week", "month", "year"] as const).map((p) => {
                const isActive = selectedPeriod === p;
                const isLoading = periodLoading && selectedPeriod === p;
                return (
                  <button
                    key={p}
                    onClick={() => handlePeriodChange(p)}
                    disabled={isLoading || isActive}
                    className={cn(
                      "px-4 py-2 font-medium transition-colors border-b-2 relative outline-none focus-visible:ring-2 focus-visible:ring-[#50B78B]/60 rounded-sm flex items-center gap-2",
                      isActive
                        ? "border-[#50B78B] text-[#50B78B] bg-linear-to-t from-[#50B78B]/12 to-transparent dark:from-[#50B78B]/12"
                        : "border-transparent text-muted-foreground hover:text-[#50B78B] cursor-pointer",
                      isLoading && "opacity-70"
                    )}
                  >
                    {periodLabels[p]}
                    {isLoading && (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    )}
                  </button>
                );
              })}
            </div>

            {/* Entries per page selector */}
            <div className="flex items-center gap-2">
              <label htmlFor="page-size-select" className="text-sm text-muted-foreground whitespace-nowrap">
                Show
              </label>
              <Select
                value={pageSize === Infinity ? "all" : pageSize.toString()}
                onValueChange={(value) => {
                  if (value === "all") {
                    updatePageSize("all");
                  } else {
                    updatePageSize(parseInt(value, 10));
                  }
                }}
              >
                <SelectTrigger
                  id="page-size-select"
                  size="sm"
                  className="h-9 w-24 border border-[#50B78B]/30 hover:bg-[#50B78B]/20 focus-visible:ring-2 focus-visible:ring-[#50B78B]"
                  aria-label="Select number of entries per page"
                >
                  <SelectValue placeholder="All" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="10">10</SelectItem>
                  <SelectItem value="25">25</SelectItem>
                  <SelectItem value="50">50</SelectItem>
                  <SelectItem value="100">100</SelectItem>
                  <SelectItem value="all">All</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          {periodLoading ? (
            <LeaderboardCardsSkeleton 
              count={pageSize === Infinity ? 10 : Math.min(pageSize, 10)} 
              variant={viewMode === "grid" ? "grid" : "list"} 
            />
          ) : filteredEntries.length === 0 ? (
            <Card>
              <CardContent className="py-16 text-center">
                <div className="relative mx-auto w-20 h-20 mb-6">
                  <div className="absolute inset-0 rounded-full bg-[#50B78B]/10 dark:bg-[#50B78B]/15" />
                  <div className="absolute inset-2 rounded-full bg-[#50B78B]/5 dark:bg-[#50B78B]/10 flex items-center justify-center">
                    <SearchX className="h-8 w-8 text-[#50B78B]/70" />
                  </div>
                </div>
                <h3 className="text-lg font-semibold mb-2">No results found</h3>
                <p className="text-muted-foreground mb-6">
                  {entries.length === 0
                    ? "No contributors with points in this period"
                    : searchQuery
                      ? `No contributors matching "${searchQuery}"`
                      : "No contributors match the selected filters"}
                </p>
                {(searchQuery || selectedRoles.size > 0 || sortBy !== "points") && (
                  <Button
                    variant="outline"
                    onClick={clearFilters}
                    className="border-[#50B78B]/30 hover:bg-[#50B78B]/20 hover:text-[#50B78B]"
                  >
                    <X className="h-4 w-4 mr-2" />
                    Clear Filters
                  </Button>
                )}
              </CardContent>
            </Card>
          ) : (
            <div className={cn(
              viewMode === "grid"
                ? "grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-6 items-stretch"
                : "grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-1 gap-4 lg:gap-0 lg:space-y-4 lg:block items-stretch"
            )}>
              {paginatedEntries.map((entry, index) => {
                // Use the pre-computed rank from entryRanks, which is based on full sorted list
                // This ensures rank doesn't change with search or pagination
                const rank = entryRanks.get(entry.username) || 1;
                return (
                  <LeaderboardCard
                    key={entry.username}
                    entry={entry}
                    rank={rank}
                    startDate={startDate}
                    endDate={endDate}
                    variant={viewMode === "grid" ? "grid" : "list"}
                  />
                );
              })}
            </div>
          )}

          {/* Pagination Controls */}
          {!periodLoading && pageSize !== Infinity && totalPages > 1 && filteredEntries.length > 0 && (
            <div className="flex items-center justify-center gap-2 mt-8">
              <Button
                variant="outline"
                size="sm"
                onClick={goToPreviousPage}
                disabled={currentPage === 1}
                className="h-9 border border-[#50B78B]/30 hover:bg-[#50B78B]/20 disabled:opacity-50 disabled:cursor-not-allowed"
                aria-label="Go to previous page"
              >
                <ChevronLeft className="h-4 w-4" />
                <span className="sr-only">Previous</span>
              </Button>

              <div className="flex items-center gap-1">
                {/* Calculate which page numbers to show */}
                {(() => {
                  const pages: number[] = [];

                  if (totalPages <= 7) {
                    // Show all pages if 7 or fewer
                    for (let i = 1; i <= totalPages; i++) {
                      pages.push(i);
                    }
                  } else {
                    // Always show first page
                    pages.push(1);

                    if (currentPage <= 4) {
                      // Show first 5 pages, then ellipsis, then last
                      for (let i = 2; i <= 5; i++) {
                        pages.push(i);
                      }
                      pages.push(-1); // -1 represents ellipsis
                      pages.push(totalPages);
                    } else if (currentPage >= totalPages - 3) {
                      // Show first, ellipsis, then last 5 pages
                      pages.push(-1); // -1 represents ellipsis
                      for (let i = totalPages - 4; i <= totalPages; i++) {
                        pages.push(i);
                      }
                    } else {
                      // Show first, ellipsis, current-1, current, current+1, ellipsis, last
                      pages.push(-1); // -1 represents ellipsis
                      pages.push(currentPage - 1);
                      pages.push(currentPage);
                      pages.push(currentPage + 1);
                      pages.push(-1); // -1 represents ellipsis
                      pages.push(totalPages);
                    }
                  }

                  return pages.map((pageNum, idx) => {
                    if (pageNum === -1) {
                      return (
                        <span key={`ellipsis-${idx}`} className="px-2 text-muted-foreground">
                          …
                        </span>
                      );
                    }
                    return (
                      <Button
                        key={pageNum}
                        variant={currentPage === pageNum ? "default" : "ghost"}
                        size="sm"
                        onClick={() => goToPage(pageNum)}
                        className={cn(
                          "h-9 w-9 p-0",
                          currentPage === pageNum
                            ? "bg-[#50B78B] text-white hover:bg-[#50B78B]/90"
                            : "hover:bg-[#50B78B]/20 hover:text-[#50B78B]"
                        )}
                        aria-label={`Go to page ${pageNum}`}
                        aria-current={currentPage === pageNum ? "page" : undefined}
                      >
                        {pageNum}
                      </Button>
                    );
                  });
                })()}
              </div>

              <Button
                variant="outline"
                size="sm"
                onClick={goToNextPage}
                disabled={currentPage === totalPages}
                className="h-9 border border-[#50B78B]/30 hover:bg-[#50B78B]/20 disabled:opacity-50 disabled:cursor-not-allowed"
                aria-label="Go to next page"
              >
                <ChevronRight className="h-4 w-4" />
                <span className="sr-only">Next</span>
              </Button>
            </div>
          )}
        </div>

        {/* Sidebar - Top Contributors by Activity */}
        {Object.keys(filteredTopByActivity).length > 0 && (
          <div className="hidden xl:block w-80 shrink-0">
            <div>
              <h2 className="text-xl font-bold mb-6">Top Contributors</h2>
              <div className="space-y-4">
                {Object.entries(filteredTopByActivity).map(
                  ([activityName, contributors]) => {
                    const style = getActivityStyle(activityName);

                    return (
                      <Card key={activityName} className="overflow-hidden p-0">
                        <CardContent className="p-0">
                          <div className={cn(
                            "px-4 py-2.5 border-b border-l-4",
                            style.bgColor,
                            style.borderColor
                          )}>
                            <h3 className={cn("font-semibold text-sm", style.textColor)}>
                              {activityName}
                            </h3>
                          </div>
                          <div className="p-3 space-y-2">
                            {contributors.map((contributor, index) => (
                              <Link
                                key={contributor.username}
                                href={`/${contributor.username}`}
                                className="flex items-center gap-2.5 p-2 rounded-md hover:bg-accent transition-colors group"
                              >
                                <div className="flex items-center justify-center w-5 h-5 shrink-0">
                                  {index === 0 && (
                                    <Trophy className="h-4 w-4 text-[#50B78B]" />
                                  )}
                                  {index === 1 && (
                                    <Medal className="h-4 w-4 text-zinc-400" />
                                  )}
                                  {index === 2 && (
                                    <Medal className="h-4 w-4 text-[#50B78B]/70" />
                                  )}
                                </div>
                                <Avatar className="h-9 w-9 shrink-0 border">
                                  <AvatarImage
                                    src={contributor.avatar_url || undefined}
                                    alt={contributor.name || contributor.username}
                                  />
                                  <AvatarFallback className="text-xs">
                                    {(contributor.name || contributor.username)
                                      .substring(0, 2)
                                      .toUpperCase()}
                                  </AvatarFallback>
                                </Avatar>
                                <div className="flex-1 min-w-0">
                                  <p className="text-sm font-medium truncate group-hover:text-[#50B78B] transition-colors leading-tight">
                                    {contributor.name || contributor.username}
                                  </p>
                                  <div className="flex items-center gap-2 mt-0.5 text-xs text-muted-foreground">
                                    <span>{contributor.count} {contributor.count === 1 ? "activity" : "activities"}</span>
                                    <span>·</span>
                                    <span>{contributor.points} pts</span>
                                  </div>
                                </div>
                              </Link>
                            ))}
                          </div>
                        </CardContent>
                      </Card>
                    );
                  }
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { Release } from "@/lib/releases";
import { ReleaseCard } from "./ReleaseCard";

export default function ReleasesClient({
  releases,
}: {
  releases: Release[];
}) {
  const [activeRepo, setActiveRepo] =
    useState<"Mobile App" | "Vue Simulator">("Mobile App");

  const filtered = releases.filter(
    (r) => r.repo === activeRepo
  );

  return (
    <div className="mt-6 space-y-6">
      {/* Tabs */}
      <div
  role="tablist"
  aria-label="Release repositories"
  className="flex gap-6 border-b pb-2"
>
  <button
    role="tab"
    aria-selected={activeRepo === "Mobile App"}
    aria-controls="mobile-panel"
    onClick={() => setActiveRepo("Mobile App")}
    className={`px-4 py-1.5 rounded-md transition-all duration-200 font-semibold cursor-pointer focus:outline-none focus-visible:ring-2 focus-visible:ring-[#50B78B]/40
      ${activeRepo === "Mobile App"
        ? "text-[#50B78B] bg-[#50B78B]/10 shadow-sm"
        : "text-zinc-500 hover:bg-[#50B78B]/10 hover:text-[#50B78B] active:bg-[#50B78B]/20"}
    `}
  >
    Mobile App
  </button>

  <button
    role="tab"
    aria-selected={activeRepo === "Vue Simulator"}
    aria-controls="vue-panel"
    onClick={() => setActiveRepo("Vue Simulator")}
    className={`px-4 py-1.5 rounded-md transition-all duration-200 font-semibold cursor-pointer focus:outline-none focus-visible:ring-2 focus-visible:ring-[#50B78B]/40
      ${activeRepo === "Vue Simulator"
        ? "text-[#50B78B] bg-[#50B78B]/10 shadow-sm"
        : "text-zinc-500 hover:bg-[#50B78B]/10 hover:text-[#50B78B] active:bg-[#50B78B]/20"}
    `}
  >
    Vue Simulator
  </button>
</div>
  

      {/* Content */}
      {filtered.length === 0 ? (
        <p className="text-sm text-zinc-500">
          No releases yet for {activeRepo}.
        </p>
      ) : (
        filtered.map((release) => (
          <ReleaseCard
            key={`${release.repoSlug}-${release.version}`}
            release={release}
          />
        ))
      )}
    </div>
  );
}
function setActiveRepo(arg0: string): void {
  throw new Error("Function not implemented.");
}

"use client";

import { useState } from "react";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import Link from "next/link";
import {
  ArrowRight,
  GitPullRequest,
  CircleDot,
  Star,
  LayoutGrid,
  GitFork,
  GitMerge,
  Trophy,
  Search,
  X,
} from "lucide-react";
import { cn } from "@/lib/utils";
import Image from "next/image";

import { ActivityTypes } from "@/components/Leaderboard/stats-card/activity-types";
import { ActivityLineCard } from "@/components/Leaderboard/stats-card/activity-line-card";
import ActiveContributors from "@/components/Leaderboard/stats-card/active-contributors";
import { PaginatedActivitySection } from "@/components/PaginatedActivitySection";
import { ActivityGroup, MonthBuckets } from "@/lib/db";
import { Config } from "@/types/config";
import { RepoStats } from "@/scripts/generateLeaderboard";
import { Users, Flame } from "lucide-react";

// --- Types ---
type ViewState = "overview" | "repositories";

type MetricVariant = "neutral" | "active" | "success";

type MetricFlowItemProps = {
  icon: React.ReactNode;
  count: number;
  label: string;
  variant: MetricVariant;
};

type OverviewData = {
  totalMonth: number;
  week: ActivityGroup[];
  month: ActivityGroup[];
  previousMonthCount: number;
  bucketData: MonthBuckets;
  config: Config;
  reposData: {
    reposOverview: RepoStats[];
  };
};

type SummaryCardProps = {
  label: string;
  value: string | number;
  sub?: string;
  icon: React.ReactNode;
  highlight?: boolean;
  decoration?: "bar" | "graph" | "wave";
};

export default function HomeDashboard({
  overviewData,
}: {
  overviewData: OverviewData;
}) {
  const [activeTab, setActiveTab] = useState<ViewState>("overview");
  const {
    config,
    week,
    month,
    previousMonthCount,
    bucketData,
    totalMonth,
    reposData,
  } = overviewData;

  const repos = reposData.reposOverview;

  // Control Bar State 
  const [search, setSearch] = useState("");
  const [language, setLanguage] = useState<string>("__all__");
  const [sort, setSort] = useState("contributions");

  //  Language Options 
  const languageOptions = Array.from(
    new Set(repos.map((r) => r.language).filter((lang): lang is string => typeof lang === "string" && !!lang))
  ).sort();

  // Filtering & Sorting Logic 
  const filteredRepos = repos
    .filter((repo) =>
      repo.name.toLowerCase().includes(search.toLowerCase())
    )
    .filter((repo) =>
      language === "__all__" ? true : repo.language === language
    );

  const sortedRepos = [...filteredRepos].sort((a, b) => {
    switch (sort) {
      case "stars":
        return b.stars - a.stars;
      case "forks":
        return b.forks - a.forks;
      case "issues":
        return b.open_issues - a.open_issues;
      case "prs":
        return b.current.pr_opened + b.current.pr_merged - (a.current.pr_opened + a.current.pr_merged);
      case "contributions":
      default:
        return b.current.currentTotalContribution - a.current.currentTotalContribution;
    }
  });

  // --- Logic to find most active repo ---
  function getActiveRepoStats() {
    if (!repos || repos.length === 0) {
      return {
        name: "N/A",
        growth: 0,
        totalContributions: 0,
      };
    }
    const topRepo = [...repos].sort(
      (a, b) =>
        b.current.currentTotalContribution - a.current.currentTotalContribution,
    )[0];
    return {
      name: topRepo?.name,
      growth: topRepo?.growth?.pr_merged ?? 0,
      totalContributions: topRepo?.current.currentTotalContribution,
    };
  }
  const activeRepo = getActiveRepoStats();

  return (
    <div className="min-h-screen transition-colors">
      <div className="mx-auto max-w-7xl px-4 sm:px-6 py-6 sm:py-10 space-y-8 sm:space-y-10">
        {/* --- 1. Header --- */}
        <section className="text-center space-y-6">
          <div className="space-y-4">
            {/* Responsive Text Size */}
            <h1 className="text-4xl sm:text-5xl lg:text-7xl font-bold tracking-tight bg-clip-text text-transparent bg-linear-to-r from-[#50B78B] via-[#60C79B] to-[#70D7AB] px-2">
              {config.org.name}
            </h1>
            <p className="max-w-2xl mx-auto text-sm sm:text-base text-zinc-600 dark:text-zinc-400 px-4">
              {config.org.description}
            </p>
          </div>

          <div className="flex justify-center mt-6">
            <div className="inline-flex items-center p-1.5 rounded-full bg-zinc-100 dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 shadow-sm relative w-full sm:w-auto max-w-xs sm:max-w-none">
              {/* Buttons are flex-1 to ensure equal width on mobile */}
              <button
                onClick={() => setActiveTab("overview")}
                className={cn(
                  "flex-1 sm:flex-none px-6 sm:px-8 py-2 rounded-full text-sm font-medium transition-all duration-300 relative z-10",
                  activeTab === "overview"
                    ? "bg-[#50B78B] text-white shadow-md"
                    : "text-zinc-500 hover:text-zinc-900 dark:hover:text-zinc-200",
                )}
              >
                Overview
              </button>
              <button
                onClick={() => setActiveTab("repositories")}
                className={cn(
                  "flex-1 sm:flex-none px-6 sm:px-8 py-2 rounded-full text-sm font-medium transition-all duration-300 relative z-10",
                  activeTab === "repositories"
                    ? "bg-[#50B78B] text-white shadow-md"
                    : "text-zinc-500 hover:text-zinc-900 dark:hover:text-zinc-200",
                )}
              >
                Repositories
              </button>
            </div>
          </div>
        </section>

        {/* --- 2. Content Area --- */}
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          {activeTab === "overview" && (
            <div className="space-y-10 sm:space-y-14">
              {/* Stats Grid - 1 Col Mobile, 2 Col Tablet, 3 Col Desktop */}
              <section className="grid gap-6 select-none grid-cols-1 sm:grid-cols-2 lg:grid-cols-3">
                <ActivityLineCard
                  totalActivitiesLabel={totalMonth}
                  prev_month={previousMonthCount}
                  week1={bucketData.w1}
                  week2={bucketData.w2}
                  week3={bucketData.w3}
                  week4={bucketData.w4}
                />
                <ActiveContributors data={month} />
                <ActivityTypes entries={month} totalActivities={totalMonth} />
              </section>

              <section className="space-y-6 max-w-5xl mx-auto">
                <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
                  <h2 className="text-xl sm:text-2xl font-bold text-[#50B78B]">
                    Recent Activities
                  </h2>
                  <Link
                    href="/leaderboard"
                    className="flex items-center gap-2 text-sm font-medium text-[#50B78B] hover:underline"
                  >
                    View Leaderboard <ArrowRight className="h-4 w-4" />
                  </Link>
                </div>
                {week.length === 0 ? (
                  <div className="rounded-2xl border border-zinc-200 dark:border-zinc-800 p-10 text-center text-zinc-500">
                    No activity in this period
                  </div>
                ) : (
                  <div className="space-y-8">
                    {week.map((group: ActivityGroup) => (
                      <PaginatedActivitySection
                        key={group.activity_definition}
                        group={group}
                        itemsPerPage={10}
                      />
                    ))}
                  </div>
                )}
              </section>
            </div>
          )}

          {/* REPOSITORIES TAB */}
          {activeTab === "repositories" && (
            <div className="space-y-8 sm:space-y-10">
              {/* Summary Cards Grid */}
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
                <SummaryCard
                  label="Total Repositories"
                  value={repos.length}
                  icon={<LayoutGrid className="h-6 w-6" />}
                  decoration="bar"
                />
                <SummaryCard
                  label="Top Repo Contributions"
                  value={activeRepo.totalContributions ?? ""}
                  sub="Last 30 Days"
                  icon={<GitFork className="h-6 w-6" />}
                  decoration="graph"
                />
                {/* Spans full width on tablet to look better */}
                <div className="sm:col-span-2 lg:col-span-1">
                  <SummaryCard
                    label="Most Active Repo"
                    value={activeRepo.name ?? ""}
                    sub={`${activeRepo.growth >= 0 ? "+" : ""}${activeRepo.growth} Merged PRs`}
                    icon={<Trophy className="h-6 w-6" />}
                    highlight={true}
                    decoration="wave"
                  />
                </div>
              </div>

              {/* Repos Grid with Control Bar */}
              <section className="space-y-6">
                {/* --- Control Bar --- */}
                <div className="flex flex-col sm:flex-row sm:items-end justify-between border-b border-zinc-200 dark:border-zinc-800 pb-2 gap-2">
                  <div className="flex flex-col sm:flex-row gap-2 w-full sm:w-auto">
                    {/* Search Bar with Icon */}
                    <div className="relative w-full sm:w-56">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
                      <Input
                        type="text"
                        placeholder="Search repositories..."
                        aria-label="Search repositories"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="pl-9 w-full bg-white dark:bg-[#07170f] border border-[#50B78B]/60 dark:border-[#50B78B]/40 focus-visible:ring-2 focus-visible:ring-[#50B78B]"
                      />
                    </div>
                    {/* Language Filter */}
                    <Select
                      value={language}
                      onValueChange={setLanguage}
                    >
                      <SelectTrigger className="w-full sm:w-40 h-9 border border-[#50B78B]/30 hover:bg-[#50B78B]/20 focus-visible:ring-2 focus-visible:ring-[#50B78B]">
                        <SelectValue placeholder="All Languages" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="__all__">All Languages</SelectItem>
                        {languageOptions.map((lang) => (
                          <SelectItem key={lang} value={lang}>
                            {lang}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    {/* Sort Dropdown */}
                    <Select
                      value={sort}
                      onValueChange={setSort}
                    >
                      <SelectTrigger className="w-full sm:w-44 h-9 border border-[#50B78B]/30 hover:bg-[#50B78B]/20 focus-visible:ring-2 focus-visible:ring-[#50B78B]">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="contributions">Most Contributions</SelectItem>
                        <SelectItem value="stars">Most Stars</SelectItem>
                        <SelectItem value="forks">Most Forks</SelectItem>
                        <SelectItem value="issues">Most Issues</SelectItem>
                        <SelectItem value="prs">Most PRs</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <span className="self-start sm:self-auto text-xs font-mono text-zinc-500 bg-zinc-100 dark:bg-zinc-800 px-2 py-1 rounded-md">
                    Showing {sortedRepos.length}
                  </span>
                </div>

                {/* --- Repo Grid or No Results --- */}
                {sortedRepos.length === 0 ? (
                  <div className="py-16 text-center rounded-2xl border border-zinc-200 dark:border-zinc-800 bg-white/60 dark:bg-zinc-900/40 shadow-sm">
                    <div className="relative mx-auto w-20 h-20 mb-6">
                      <div className="absolute inset-0 rounded-full bg-[#50B78B]/10 dark:bg-[#50B78B]/15" />
                      <div className="absolute inset-2 rounded-full bg-[#50B78B]/5 dark:bg-[#50B78B]/10 flex items-center justify-center">
                        <Search className="h-8 w-8 text-[#50B78B]/70" />
                      </div>
                    </div>
                    <h3 className="text-lg font-semibold mb-2">No results found</h3>
                    <p className="text-muted-foreground mb-6">
                      {search
                        ? `No repositories matching "${search}"`
                        : "No repositories match the selected filters"}
                    </p>
                    {(search || language !== "__all__" || sort !== "contributions") && (
                      <button
                        type="button"
                        onClick={() => {
                          setSearch("");
                          setLanguage("__all__");
                          setSort("contributions");
                        }}
                        className="inline-flex items-center gap-2 px-4 py-2 rounded-md border border-[#50B78B]/30 bg-[#50B78B]/10 text-[#50B78B] font-medium hover:bg-[#50B78B]/20 transition-colors"
                      >
                        <X className="h-4 w-4" />
                        Clear Filters
                      </button>
                    )}
                  </div>
                ) : (
                  <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-4 sm:gap-6">
                    {sortedRepos.map((repo: RepoStats) => (
                      <RepoCard key={repo.name} repo={repo} />
                    ))}
                  </div>
                )}
              </section>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ===== Components =====

function SummaryCard({
  label,
  value,
  sub,
  icon,
}: SummaryCardProps) {
  return (
    <div className="flex flex-col h-full rounded-[20px] border border-zinc-200 dark:border-white/10 bg-white dark:bg-zinc-900/40 shadow-xl shadow-[#edfff7] dark:shadow-black/50 overflow-hidden">
      <div className="flex flex-row items-center justify-between p-6 pb-2">
        <p className="text-xs font-medium uppercase tracking-wider text-zinc-500 dark:text-zinc-400">
          {label}
        </p>
        <div className="text-zinc-400 dark:text-zinc-600">
          {icon}
        </div>
      </div>

      <div className="flex flex-1 flex-col justify-between p-6 pt-4">
        <div>
          <div
            className={cn(
              "font-bold tracking-tight text-[#50B78B] dark:text-white",
              String(value).length > 15
                ? "text-xl sm:text-2xl break-all"
                : "text-5xl"
            )}
          >
            {value}
          </div>
          {sub && (
            <p className="text-sm font-medium text-[#50B78B] mt-2">{sub}</p>
          )}
        </div>
      </div>
    </div>
  );
}

function RepoCard({ repo }: { repo: RepoStats }) {
  return (
    <div className="group flex flex-col h-full bg-white dark:bg-zinc-900/40 border border-zinc-200 dark:border-white/10 hover:border-[#50B78B]/30 transition-all duration-300 rounded-[20px] overflow-hidden shadow-xl shadow-[#edfff7] dark:shadow-black/50">
      {/* Top Section */}
      <div className="p-5 sm:p-6 grow space-y-4">
        <div className="flex items-start justify-between gap-3 sm:gap-4">
          {/* Avatar and Name Wrapper */}
          <div className="flex items-center gap-3 overflow-hidden min-w-0">
            <div className="shrink-0 group-hover:border-[#50B78B]/30 group-hover:text-[#50B78B] transition-colors rounded-md overflow-hidden border border-zinc-100 dark:border-zinc-800">
              <Image
                src={repo.avatar_url}
                alt={repo.name ?? "Image"}
                width={40}
                height={40}
              />
            </div>
            {/* Added min-w-0 to allow truncation inside flex */}
            <div className="min-w-0 flex-1">
              <div className="text-base sm:text-lg font-bold text-zinc-900 dark:text-zinc-100 hover:text-[#50B78B] dark:hover:text-[#50B78B] transition-colors truncate">
                <Link
                  href={repo.html_url}
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  {repo.name}
                </Link>
              </div>
              {repo.language && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-medium bg-zinc-100 dark:bg-zinc-800 text-zinc-600 dark:text-zinc-300 border border-zinc-200 dark:border-zinc-700 mt-1">
                  {repo.language}
                </span>
              )}
            </div>
          </div>

          <div className="flex flex-col items-end gap-1.5 shrink-0">
            <div className="flex items-center gap-1 text-xs font-semibold text-zinc-500 dark:text-zinc-400">
              <GitFork className="h-3.5 w-3.5 text-[#7C3AED]" />
              {repo.forks}
            </div>
            <div className="flex items-center gap-1 text-xs font-semibold text-zinc-500 dark:text-zinc-400">
              <Star className="h-3.5 w-3.5 fill-amber-400 text-amber-400" />
              {repo.stars}
            </div>
          </div>
        </div>
        <p className="text-sm text-zinc-600 dark:text-zinc-400 line-clamp-2 leading-relaxed">
          {repo.description?.trim()
            ? repo.description
            : "A CircuitVerse project repository"}
        </p>
      </div>

      {/* Metrics Section */}
      <div className="px-5 pb-5 sm:px-6 sm:pb-6 pt-0">
        <div className="grid grid-cols-3 gap-2 rounded-xl bg-zinc-50 dark:bg-zinc-800/50 p-2 border border-zinc-100 dark:border-white/5">
          <Link
            href={`${repo.html_url}/issues`}
            target="_blank"
            rel="noopener noreferrer"
          >
            <MetricFlowItem
              icon={<CircleDot className="h-4 w-4 sm:h-5 sm:w-5" />}
              count={repo.open_issues}
              label="Issues"
              variant="neutral"
            />
          </Link>
          <Link
            href={`${repo.html_url}/pulls`}
            target="_blank"
            rel="noopener noreferrer"
          >
            <MetricFlowItem
              icon={<GitPullRequest className="h-4 w-4 sm:h-5 sm:w-5" />}
              count={repo.current.pr_opened}
              label="Open"
              variant="active"
            />
          </Link>
          <Link
            href={`${repo.html_url}/pulls?q=is%3Apr+is%3Amerged`}
            target="_blank"
            rel="noopener noreferrer"
          >
            <MetricFlowItem
              icon={<GitMerge className="h-4 w-4 sm:h-5 sm:w-5" />}
              count={repo.current.pr_merged}
              label="Merged"
              variant="success"
            />
          </Link>
        </div>
      </div>

      {/* Top Contributors Section */}
      {repo.top_contributors && repo.top_contributors.length > 0 && (
        <div className="px-5 pb-5 sm:px-6 sm:pb-6 border-t border-zinc-100 dark:border-white/5 pt-4 bg-[#50B78B]/5 dark:bg-[#50B78B]/5">
          <div className="flex items-center justify-between mb-2">
            <span className="text-[10px] font-bold text-zinc-500 uppercase flex items-center gap-1">
              <Users className="w-3 h-3" />
              Top Contributors
            </span>
          </div>
          <div className="flex -space-x-2">
            {repo.top_contributors.slice(0, 5).map((contributor) => (
              <Link 
                key={contributor.username}
                href={`/people/${contributor.username}`}
                title={`${contributor.username} (${contributor.points} pts)`}
