    type: string;
    title: string;
    occured_at: string;
    link: string;
    points: number;
  }>;
  active_prs?: Array<{ title: string; link: string; updatedAt: string }>;
  stale_prs?: Array<{ title: string; link: string; updatedAt: string }>;
  streak?: {
    current: number;
    longest: number;
    lastActivityDate: string | null;
  };
}

interface ContributorDetailProps {
  contributor: ContributorEntry;
  onBack: () => void;
}

// Activity type configuration with unique visual identity
const activityConfig: Record<ActivityKey, ActivityUIConfig> = {
  "PR merged": {
    icon: <GitMerge className="w-4 h-4" />,
    gradient: "from-purple-500/10 via-purple-500/5 to-transparent",
    borderColor: "border-purple-500/30 hover:border-purple-500/50",
    bgColor: "bg-purple-500/5",
