                    <span className="text-xs text-orange-600 text-center font-medium">Longest Streak 🏆</span>
                  </div>
                  
                   <div className="flex flex-col items-center p-4 rounded-xl bg-gradient-to-br from-purple-50 via-purple-50 to-purple-100 dark:from-purple-400 dark:to-purple-300 border border-purple-200 dark:border-purple-800">
                    <Target className="w-6 h-6 text-purple-600 mb-2" />
                    <span className="font-bold text-xl text-purple-700">{averagePointsPerDay}</span>
                    <span className="text-xs text-purple-600 text-center font-medium">Avg/Day</span>
                  </div>

                  <div className="flex flex-col items-center p-4 rounded-xl bg-gradient-to-br from-pink-50 via-pink-50 to-pink-100 dark:from-pink-400 dark:to-pink-300 border border-pink-200 dark:border-pink-800">
                    <Activity className="w-6 h-6 text-pink-600 mb-2" />
                    <span className="font-bold text-xl text-pink-700">{sortedActivities.length}</span>
                    <span className="text-xs text-pink-600 text-center font-medium">Activity Types</span>
                  </div>
                </div>

                <a
                  href={`https://github.com/${contributor.username}`}
                  target="_blank" rel="noopener noreferrer"
                  className="w-full flex justify-center mt-4"
                >
                  <Button className="bg-gradient-to-r cursor-pointer from-primary to-primary/80 hover:from-primary/90 hover:to-primary/70 shadow-md">
                    <Github className="w-5 h-5" />
                  </Button>
                </a>
              </div>
            </CardContent>
          </Card>
        </div>

        <div className="lg:col-span-3 space-y-8">
          <AchievementBadges badges={earnedBadges} />

          {/* Efficiency Metrics */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Card className="bg-gradient-to-br from-indigo-500/10 to-purple-500/10 border-indigo-500/20 shadow-sm">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium flex items-center gap-2 text-indigo-600 dark:text-indigo-400">
                  <Clock className="w-4 h-4" />
                  PR Turn-around
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="flex items-baseline gap-2">
                  <span className="text-3xl font-bold">
                    {(() => {
                      const prOpened = new Map<string, number>();
                      const times: number[] = [];
                      const sorted = [...(contributor.activities || [])].sort(
                        (a, b) => new Date(a.occured_at).getTime() - new Date(b.occured_at).getTime()
                      );
                      
                      sorted.forEach(act => {
                        if (act.type === "PR opened") prOpened.set(act.link, new Date(act.occured_at).getTime());
                        else if (act.type === "PR merged" && prOpened.has(act.link)) {
                          times.push(new Date(act.occured_at).getTime() - prOpened.get(act.link)!);
                        }
                      });
                      
                      if (times.length === 0) return "N/A";
                      const avgHours = Math.round(times.reduce((a, b) => a + b, 0) / times.length / (1000 * 3600));
                      return avgHours > 24 ? `${Math.round(avgHours / 2.4) / 10} days` : `${avgHours}h`;
                    })()}
                  </span>
                  <span className="text-muted-foreground text-sm">avg. merge time</span>
                </div>
              </CardContent>
            </Card>

            <Card className="bg-gradient-to-br from-orange-500/10 to-red-500/10 border-orange-500/20 shadow-sm">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium flex items-center gap-2 text-orange-600 dark:text-orange-400">
                  <TrendingUp className="w-4 h-4" />
                  Activity Impact
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="flex items-baseline gap-2">
                  <span className="text-3xl font-bold">{currentStreak}d</span>
                  <span className="text-muted-foreground text-sm">current streak</span>
                </div>
              </CardContent>
            </Card>
          </div>
          
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="md:col-span-2">
              <Card className="bg-gradient-to-r from-primary/5 to-primary/10 border-primary/20 h-full">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2 text-primary">
                    <BarChart3 className="w-5 h-5" />
                    This Month&apos;s Activity
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                    <div className="text-center p-4 bg-background/50 rounded-lg">
                      <div className="text-2xl font-bold text-primary">{monthlyPoints}</div>
                      <div className="text-sm text-muted-foreground">Points Earned</div>
                    </div>
                    <div className="text-center p-4 bg-background/50 rounded-lg">
                      <div className="text-2xl font-bold text-primary">{monthlyDays}</div>
                      <div className="text-sm text-muted-foreground">Active Days</div>
                    </div>
                    <div className="text-center p-4 bg-background/50 rounded-lg">
                      <div className="text-2xl font-bold text-primary">{monthlyDays > 0 ? Math.round(monthlyPoints / monthlyDays) : 0}</div>
                      <div className="text-sm text-muted-foreground">Daily Average</div>
                    </div>
                    <div className="text-center p-4 bg-background/50 rounded-lg">
                      <div className="text-2xl font-bold text-primary">{monthlyActivityTypesCount}</div>
                      <div className="text-sm text-muted-foreground">Activity Types</div>
                    </div>
                    <div className="text-center p-4 bg-background/50 rounded-lg lg:col-span-2">
                      <div className="text-2xl font-bold text-primary">{(contributor.activities || []).length}</div>
                      <div className="text-sm text-muted-foreground">Total Actions Recorded</div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </div>
            
            <div className="md:col-span-1">
              <ActivityChart data={contributor.activity_breakdown} />
            </div>
          </div>


          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Activity className="w-5 h-5" />
                Activity Breakdown
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {sortedActivities.map(([activity, data]) => {
                  const config = getActivityConfig(activity);

                  return (
                    <div
                      key={activity}
                      className={`group relative p-5 rounded-xl border ${config.borderColor} bg-gradient-to-br ${config.gradient} hover:shadow-lg transition-all duration-200 overflow-hidden`}
                    >
                      {/* Accent bar on the left */}
                      <div className={`absolute left-0 top-0 bottom-0 w-1 ${config.accentColor}`} />

                      <div className="flex items-center gap-3 mb-4">
                        <div className={`p-2.5 rounded-lg ${config.iconBg} transition-colors ${config.textColor}`}>
                          {config.icon}
                        </div>
                        <div className="flex-1">
                          <h4 className={`font-semibold text-lg ${config.textColor}`}>{activity}</h4>
                          <p className="text-sm text-muted-foreground">{data.count} contributions</p>
                        </div>
                        <Badge className={`${config.bgColor} ${config.textColor} border-0 font-bold text-base px-3 py-1`}>
                          {data.points}
                        </Badge>
                      </div>

                      <div className="space-y-3 pl-1">
                        <div className="flex justify-between items-center text-sm">
                          <span className="font-medium text-muted-foreground">Average per contribution</span>
                          <span className={`font-bold ${config.textColor}`}>
                            {Math.round(data.points / data.count)} pts
                          </span>
                        </div>

                        {/* Visual progress bar */}
                        <div className="w-full h-2 bg-muted rounded-full overflow-hidden">
                          <div
                            className={`h-full ${config.accentColor} transition-all duration-300`}
                            style={{
                              width: `${Math.min(
                                maxPoints > 0 ? (data.points / maxPoints) * 100 : 0,
                                100
                              )}%`,
                            }}

                          />
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Clock className="w-5 h-5" />
                Recent Contributions
                <Badge variant="secondary" className="ml-2">{recentContributions.length}</Badge>
              </CardTitle>
            </CardHeader>
            <CardContent>
              {recentContributions.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center mb-4">
                  No contributions in the last 30 days.
                </p>
              ) : (
                <div className="space-y-3 max-h-80 overflow-y-auto pr-2">
                  {recentContributions.map((activity, index) => {
                    const date = new Date(activity.occured_at);
                    const isVeryRecent = index < 3;
                    const daysAgo = Math.floor((currentTime - date.getTime()) / (1000 * 60 * 60 * 24));
                    const config = getActivityConfig(activity.type);

                    return (
                      <div
                        key={`${activity.link}-${index}`}
                        className={`group flex items-start gap-4 p-4 rounded-lg border transition-all duration-200 hover:shadow-md ${isVeryRecent
                            ? `${config.borderColor} bg-gradient-to-r ${config.gradient}`
                            : 'bg-muted/20 hover:bg-muted/40 hover:border-primary/20'
                          }`}
                      >
                        <div className={`mt-1 p-2 rounded-lg ${config.iconBg} ${config.textColor} transition-colors`}>
                          {config.icon}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-start justify-between gap-3 mb-2">
                            <div className="flex-1 min-w-0">
                              {activity.link ? (
                                <a
                                  href={activity.link}
                                  target="_blank"
                                  rel="noopener noreferrer"
                                  className="font-medium text-sm line-clamp-2 mb-1 group-hover:text-primary transition-colors cursor-pointer hover:underline"
                                >
                                  {activity.title}
                                </a>
                              ) : (
                                <h4 className="font-medium text-sm line-clamp-2 mb-1 group-hover:text-primary transition-colors">
                                  {activity.title}
                                </h4>
                              )}
                              <div className="flex items-center gap-3 text-xs text-muted-foreground">
                                <span className={`font-medium px-2 py-1 rounded-full ${config.bgColor} ${config.textColor}`}>
                                  {activity.type}
                                </span>
                                <span className="flex items-center gap-1 whitespace-nowrap shrink-0">
                                  <Calendar className="w-3 h-3" />
                                  {daysAgo === 0 ? 'Today' : daysAgo === 1 ? 'Yesterday' : `${daysAgo} days ago`}
                                </span>
                              </div>
                            </div>
                            <div className="flex items-center gap-3 shrink-0">
                              <Badge
                                variant={isVeryRecent ? "default" : "secondary"}
                                className={`text-xs font-bold ${isVeryRecent ? `${config.bgColor} ${config.textColor} border-0` : ''}`}
                              >
                                +{activity.points} pts
                              </Badge>
                              {isVeryRecent && (
                                <div className={`w-2 h-2 ${config.accentColor} rounded-full animate-pulse`} />
                              )}
                            </div>
                          </div>
                          {activity.link && (
                            <a
                              href={activity.link}
                              target="_blank"
                              rel="noopener noreferrer"
                              className={`inline-flex items-center gap-1 text-xs hover:underline font-medium ${config.textColor}`}
                            >
                              View Contribution
                              <ExternalLink className="w-3 h-3" />
                            </a>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </CardContent>
          </Card>

          <GitHubHeatmap
            dailyActivity={recentActivity}
            className="border-primary/20"
          />

          {/* Pull Request Status Section */}
          {(contributor.active_prs?.length || 0) + (contributor.stale_prs?.length || 0) > 0 && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Active PRs */}
              <Card className="border-emerald-500/20 bg-emerald-500/5 h-full">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2 text-emerald-600 dark:text-emerald-400">
                    <FlameIcon className="w-5 h-5" />
                    Active Pull Requests
                    <Badge variant="outline" className="ml-auto border-emerald-500/30 text-emerald-600">
                      {contributor.active_prs?.length || 0}
                    </Badge>
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  {contributor.active_prs && contributor.active_prs.length > 0 ? (
                    <div className="space-y-3">
                      {contributor.active_prs.map((pr, i) => (
                        <a
                          key={i}
                          href={pr.link}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="flex items-start gap-3 p-3 rounded-lg bg-background/60 hover:bg-background border border-emerald-500/10 hover:border-emerald-500/30 transition-all group"
                        >
                          <GitPullRequest className="w-4 h-4 mt-1 text-emerald-500 shrink-0" />
                          <div className="min-w-0">
                            <p className="text-sm font-medium line-clamp-2 group-hover:text-emerald-600 transition-colors">
                              {pr.title}
                            </p>
                            <p className="text-[10px] text-muted-foreground mt-1 flex items-center gap-1">
                              <Clock className="w-2.5 h-2.5" />
                              Updated {new Date(pr.updatedAt).toLocaleDateString()}
                            </p>
                          </div>
                          <ExternalLink className="w-3 h-3 ml-auto opacity-0 group-hover:opacity-100 transition-opacity" />
                        </a>
                      ))}
                    </div>
                  ) : (
                    <p className="text-sm text-muted-foreground text-center py-4 italic">
                      No active pull requests at the moment.
                    </p>
                  )}
                </CardContent>
              </Card>

              {/* Stale PRs */}
              <Card className="border-orange-500/20 bg-orange-500/5 h-full">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2 text-orange-600 dark:text-orange-400">
                    <Clock className="w-5 h-5" />
                    Stale Pull Requests
                    <Badge variant="outline" className="ml-auto border-orange-500/30 text-orange-600">
                      {contributor.stale_prs?.length || 0}
                    </Badge>
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  {contributor.stale_prs && contributor.stale_prs.length > 0 ? (
                    <div className="space-y-3">
                      {contributor.stale_prs.map((pr, i) => (
                        <a
                          key={i}
                          href={pr.link}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="flex items-start gap-3 p-3 rounded-lg bg-background/60 hover:bg-background border border-orange-500/10 hover:border-orange-500/30 transition-all group"
                        >
                          <AlertCircle className="w-4 h-4 mt-1 text-orange-500 shrink-0" />
                          <div className="min-w-0">
                            <p className="text-sm font-medium line-clamp-2 group-hover:text-orange-600 transition-colors">
                              {pr.title}
                            </p>
                            <p className="text-[10px] text-muted-foreground mt-1 flex items-center gap-1">
                              <Clock className="w-2.5 h-2.5" />
                              Last activity: {new Date(pr.updatedAt).toLocaleDateString()}
                            </p>
                          </div>
                          <ExternalLink className="w-3 h-3 ml-auto opacity-0 group-hover:opacity-100 transition-opacity" />
                        </a>
                      ))}
                    </div>
                  ) : (
                    <p className="text-sm text-muted-foreground text-center py-4 italic">
                      No stale pull requests listed.
                    </p>
                  )}
                </CardContent>
              </Card>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { 
  Users, 
  Trophy, 
  Activity, 
  TrendingUp, 
  Star,
  GitCommit,
  Target,
  GitPullRequest
} from "lucide-react";

interface ContributorEntry {
  username: string;
  name: string | null;
  avatar_url: string;
  role: string;
  total_points: number;
  activity_breakdown: Record<string, { count: number; points: number }>;
  daily_activity: Array<{ date: string; count: number; points: number }>;
}

interface PeopleStatsProps {
  contributors: ContributorEntry[];
  allContributors: ContributorEntry[];
  onContributorClick?: (contributor: ContributorEntry) => void;
}

export function PeopleStats({ contributors, allContributors, onContributorClick }: PeopleStatsProps) {

  // Calculate stats
  const totalContributors = contributors.length;
  const totalPoints = contributors.reduce((sum, c) => sum + (c.total_points || 0), 0);
  const averagePoints = totalContributors > 0 ? Math.round(totalPoints / totalContributors) : 0;
  

  // Activity stats
  const totalActivities = contributors.reduce((sum, c) => {
    return sum + Object.values(c.activity_breakdown || {}).reduce((actSum, act) => actSum + act.count, 0);
  }, 0);

  
// GLOBAL ranking (based on full contributors list)
const topContributors = useMemo(() => {
  return [...allContributors]
    .sort((a, b) => (b.total_points || 0) - (a.total_points || 0))
    .slice(0, 5)
    .map((contributor, index) => ({
      ...contributor,
      rank: index + 1,
    }));
}, [allContributors]);


  // Active days stats
  const activeDaysData = contributors.map(c => c.daily_activity?.length || 0);
  const totalActiveDays = activeDaysData.reduce((sum, days) => sum + days, 0);
  const averageActiveDays = totalContributors > 0 ? Math.round(totalActiveDays / totalContributors) : 0;

  // Recent activity (last 7 days)
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
  
  const recentlyActive = contributors.filter(contributor => {
    const lastActivity = contributor.daily_activity?.find(day => 
      new Date(day.date) >= sevenDaysAgo
    );
    return !!lastActivity;
  }).length;

  // Calculate activity type distribution
  const activityTypes = contributors.reduce((acc, contributor) => {
    Object.entries(contributor.activity_breakdown || {}).forEach(([type, data]) => {
      if (!acc[type]) acc[type] = { count: 0, points: 0 };
      acc[type].count += data.count;
      acc[type].points += data.points;
    });
    return acc;
  }, {} as Record<string, { count: number; points: number }>);

  const topActivityTypes = Object.entries(activityTypes)
    .sort(([, a], [, b]) => b.points - a.points)
    .slice(0, 4);

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <Card className="bg-gradient-to-br from-green-600 to-emerald-600 dark:from-green-500 dark:to-emerald-700 border-green-300 dark:border-emerald-600 shadow-lg hover:shadow-2xl transition-all duration-300">
          <CardContent className="p-6">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-white/20 dark:bg-white/10 rounded-xl shadow-sm">
                <Users className="w-6 h-6 text-white" />
              </div>
              <div>
                <p className="text-md text-white/80">Total Contributors</p>
                <p className="text-2xl font-bold text-white">{totalContributors}</p>
                <p className="text-sm text-white/70">Active community</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-amber-600 to-orange-600 dark:from-amber-500 dark:to-orange-700 border-amber-300 dark:border-orange-600 shadow-lg hover:shadow-2xl transition-all duration-300">
          <CardContent className="p-6">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-white/20 dark:bg-white/10 rounded-xl shadow-sm">
                <Trophy className="w-6 h-6 text-white" />
              </div>
              <div>
                <p className="text-md text-white/80">Total Points</p>
                <p className="text-2xl font-bold text-white">{totalPoints.toLocaleString()}</p>
                <p className="text-sm text-white/70">Community effort</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-blue-600 to-cyan-600 dark:from-blue-500 dark:to-cyan-700 border-blue-300 dark:border-cyan-600 shadow-lg hover:shadow-2xl transition-all duration-300">
          <CardContent className="p-6">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-white/20 dark:bg-white/10 rounded-xl shadow-sm">
                <Target className="w-6 h-6 text-white" />
              </div>
              <div>
                <p className="text-md text-white/80">Avg Points</p>
                <p className="text-2xl font-bold text-white">{averagePoints}</p>
                <p className="text-sm text-white/70">Per contributor</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-purple-600 to-pink-600 dark:from-purple-500 dark:to-pink-700 border-purple-300 dark:border-pink-600 shadow-lg hover:shadow-2xl transition-all duration-300">
          <CardContent className="p-6">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-white/20 dark:bg-white/10 rounded-xl shadow-sm">
                <TrendingUp className="w-6 h-6 text-white" />
              </div>
              <div>
                <p className="text-md text-white/80">Active This Year</p>
                <p className="text-2xl font-bold text-white">{recentlyActive}</p>
                <p className="text-sm text-white/70">{totalContributors > 0 ? Math.round((recentlyActive/totalContributors)*100) : 0}% of community</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Star className="w-5 h-5 text-yellow-500" />
              Top Contributors of the year
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {topContributors.map((contributor, index) => (
                <div 
                  key={contributor.username} 
                  className="flex items-center gap-3 p-3 rounded-lg bg-muted/30 hover:bg-muted/50 transition-colors cursor-pointer"
                  onClick={() => onContributorClick?.(contributor)}
                >
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${{
                    0: 'bg-gradient-to-br from-yellow-400 to-yellow-600 text-white shadow-md',
                    1: 'bg-gradient-to-br from-gray-300 to-gray-500 text-white shadow-md',
                    2: 'bg-gradient-to-br from-amber-400 to-amber-600 text-white shadow-md'
                  }[index] || 'bg-gradient-to-br from-primary/20 to-primary/40 text-primary font-semibold'}`}>
                    {contributor.rank}
                  </div>
                  <img 
                    src={contributor.avatar_url} 
                    alt={contributor.name || contributor.username}
                    className="w-10 h-10 rounded-full ring-2 ring-primary/10"
                  />
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-sm truncate">
                      {contributor.name || contributor.username}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      @{contributor.username} • {contributor.role}
                    </p>
                  </div>
                  <div className="text-right">
                    <Badge variant="outline" className="font-bold">
                      {contributor.total_points || 0} pts
                    </Badge>
                    <p className="text-xs text-muted-foreground mt-1">
                      {contributor.daily_activity?.length || 0} active days
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Activity className="w-5 h-5" />
              Activity Overview
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-2 gap-4 mb-6">
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-green-600 dark:text-green-400">{totalActivities.toLocaleString()}</div>
                <div className="text-sm text-muted-foreground">Total Activities</div>
              </div>
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-green-600 dark:text-green-400">{averageActiveDays}</div>
                <div className="text-sm text-muted-foreground">Avg Active Days</div>
              </div>
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-green-600 dark:text-green-400">{Math.round(totalActivities / totalContributors)}</div>
                <div className="text-sm text-muted-foreground">Avg Activities</div>
              </div>
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-green-600 dark:text-green-400">{Math.round((recentlyActive / totalContributors) * 100)}%</div>
                <div className="text-sm text-muted-foreground">Weekly Active Rate</div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {topActivityTypes.map(([type, data]) => {
                const getActivityIcon = (activityType: string) => {
                  const typeStr = activityType.toLowerCase();
                  if (typeStr.includes('commit')) return <GitCommit className="w-4 h-4" />;
                  if (typeStr.includes('pr') || typeStr.includes('pull')) return <GitPullRequest className="w-4 h-4" />;
                  if (typeStr.includes('issue')) return <Activity className="w-4 h-4" />;
                  return <Activity className="w-4 h-4" />;
                };

                return (
                  <div key={type} className="p-3 border rounded-lg bg-gradient-to-br from-background to-muted/30">
                    <div className="flex items-center gap-2 mb-2">
                      {getActivityIcon(type)}
                      <span className="font-medium text-sm truncate">{type}</span>
                    </div>
                    <div className="space-y-1">
                      <div className="text-lg font-bold text-green-600 dark:text-green-400">{data.count}</div>
                      <div className="text-xs text-muted-foreground">{data.points} total points</div>
                    </div>
                  </div>
                );
              })}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

